import { NextRequest, NextResponse } from 'next/server'
import { getRequestContext } from '@cloudflare/next-on-pages'

export const runtime = 'edge'

export async function GET(request: NextRequest) {
  try {
    const { env } = getRequestContext()

    // Graceful fallback for local development or missing binding
    if (!env || !env.DB) {
      console.warn("[v0] Database 'DB' binding missing. Returning empty array.")
      return NextResponse.json([], { status: 200 })
    }

    try {
      const stmt = await env.DB.prepare(
        "SELECT * FROM products WHERE isActive = 1 ORDER BY createdAt DESC"
      ).all()

      const results = stmt?.results || []

      const products = results.map((p: any) => {
        // Safe JSON parse for tags
        let tags = [];
        try {
          if (p.tags) {
            // Handle both stringified JSON and potential direct format if D1 changes behavior
            tags = typeof p.tags === 'string' ? JSON.parse(p.tags) : p.tags;
          }
        } catch (e) {
          console.warn(`[v0] Failed to parse tags for product ${p.id}`, p.tags);
          tags = [];
        }

        return {
          id: p.id,
          title: p.title || '',
          description: p.description || '',
          price: p.price || 0,
          discountPrice: p.discountPrice || null,
          category: p.category || 'software',
          tags: Array.isArray(tags) ? tags : [],
          imageUrl: p.imageUrl || '',
          downloadUrl: p.downloadUrl || '',
          isActive: Boolean(p.isActive),
          salesCount: p.salesCount || 0,
          pageCode: p.pageCode,
          createdBy: p.createdBy || '',
          createdAt: new Date(p.createdAt),
          updatedAt: new Date(p.updatedAt)
        };
      })

      return NextResponse.json(products, { status: 200 })
    } catch (dbError: any) {
      console.error("[v0] DB Query Error:", dbError.message);
      // Return empty array instead of 500 so UI doesn't crash
      return NextResponse.json([], { status: 200 });
    }
  } catch (err: any) {
    console.error("[v0] Products API Critical Error:", err.message)
    return NextResponse.json([], { status: 200 }) 
  }
}

export async function POST(request: NextRequest) {
  try {
    const { env } = getRequestContext()

    if (!env || !env.DB) {
      return NextResponse.json({ error: "Database not available" }, { status: 503 })
    }

    const data = await request.json()

    if (!data.title || !data.price) {
      return NextResponse.json({ error: "Title and price are required" }, { status: 400 })
    }

    const id = crypto.randomUUID()
    const now = Date.now()

    await env.DB.prepare(`
      INSERT INTO products (id, title, description, price, category, tags, imageUrl, downloadUrl, isActive, salesCount, pageCode, createdBy, createdAt, updatedAt)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    `).bind(
      id, 
      data.title || '', 
      data.description || '', 
      data.price || 0, 
      data.category || 'software', 
      JSON.stringify(data.tags || []), 
      data.imageUrl || '', 
      data.downloadUrl || '', 
      data.isActive ? 1 : 0, 
      0, 
      data.pageCode || null, 
      data.createdBy || 'admin', 
      now, 
      now
    ).run()

    return NextResponse.json({ success: true, id }, { status: 201 })
  } catch (err: any) {
    console.error("[v0] POST Products Error:", err.message)
    return NextResponse.json({ error: err.message }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { getRequestContext } from '@cloudflare/next-on-pages'

export const runtime = 'edge'

// GET: Fetch all orders
export async function GET(request: NextRequest) {
  try {
    const { env } = getRequestContext()

    if (!env || !env.DB) {
      return NextResponse.json([], { status: 200 })
    }

    try {
      const stmt = await env.DB.prepare(
        "SELECT * FROM orders ORDER BY createdAt DESC"
      ).all()

      const results = stmt?.results || []

      const orders = results.map((o: any) => {
        let items = [];
        try {
          items = o.items ? (typeof o.items === 'string' ? JSON.parse(o.items) : o.items) : [];
        } catch (e) { items = []; }

        return {
          id: o.id,
          userId: o.userId,
          items: items,
          totalAmount: o.totalAmount || 0,
          status: o.status || 'pending',
          paymentId: o.paymentId,
          createdAt: new Date(o.createdAt),
          updatedAt: new Date(o.updatedAt)
        };
      })

      return NextResponse.json(orders, { status: 200 })
    } catch (dbErr) {
      console.error("[v0] Orders Query Error:", dbErr);
      return NextResponse.json([], { status: 200 });
    }
  } catch (err: any) {
    console.error("[v0] Orders API Error:", err.message)
    return NextResponse.json([], { status: 200 })
  }
}

// POST: Create a new order
export async function POST(request: NextRequest) {
  try {
    const { env } = getRequestContext()

    if (!env || !env.DB) {
      return NextResponse.json({ error: "Database not available" }, { status: 503 })
    }

    const data = await request.json()

    if (!data.userId || !data.items || !data.totalAmount) {
      return NextResponse.json({ error: "Missing required fields" }, { status: 400 })
    }

    const id = "ORD-" + crypto.randomUUID().slice(0, 8).toUpperCase()
    const now = Date.now()

    await env.DB.prepare(`
      INSERT INTO orders (id, userId, items, totalAmount, status, paymentId, createdAt, updatedAt)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?)
    `).bind(
      id,
      data.userId,
      JSON.stringify(data.items || []),
      data.totalAmount || 0,
      data.status || 'pending',
      data.paymentId || null,
      now,
      now
    ).run()

    return NextResponse.json({ success: true, id }, { status: 201 })
  } catch (err: any) {
    console.error("[v0] POST Orders Error:", err.message)
    return NextResponse.json({ error: err.message }, { status: 500 })
  }
}

